#include <bits/stdc++.h>
using namespace std;

void solve() {
    int n;
    cin >> n;
    vector<long long> arr(n);

    for(int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    // Sort in descending order
    sort(arr.begin(), arr.end());

    // Check consecutive triplets
    bool possible = false;
    for(int i = 0; i < n-2; i++) {
        if(arr[i] + arr[i+1] > arr[i+2]) {
            possible = true;
            break;
        }
    }

    cout << (possible ? "YES" : "NO") << "\n";
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        solve();
    }
    return 0;
}
